# tests/architecture/test_dependency_fitness.py
import ast, pathlib, pytest

ALLOWED_SDK_IMPORTERS = {
    "src/claude/client.py",
    "src/claude/streaming.py",
    "tests/",  # test files may import for mocking
}

def find_anthropic_imports(repo_root: pathlib.Path) -> list[tuple[str, int]]:
    violations = []
    for py_file in repo_root.rglob("*.py"):
        rel = str(py_file.relative_to(repo_root))
        if any(rel.startswith(allowed) for allowed in ALLOWED_SDK_IMPORTERS):
            continue
        try:
            tree = ast.parse(py_file.read_text())
        except SyntaxError:
            continue
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom)):
                names = [a.name for a in node.names] if isinstance(node, ast.Import) else [node.module or ""]
                if any("anthropic" in (n or "") for n in names):
                    violations.append((rel, node.lineno))
    return violations

def test_anthropic_sdk_only_in_integration_layer():
    """Only the designated integration layer may import the Anthropic SDK."""
    repo_root = pathlib.Path(__file__).parent.parent.parent
    violations = find_anthropic_imports(repo_root)
    assert not violations, (
        "Anthropic SDK imported outside the integration layer:\n" +
        "\n".join(f"  {file}:{line}" for file, line in violations)
    )

