import ast, pathlib

ALLOWED_CLIENT_CONSTRUCTORS = {"src/claude/client.py"}

def find_client_constructors(repo_root: pathlib.Path) -> list[tuple[str, int]]:
    violations = []
    for py_file in repo_root.rglob("*.py"):
        rel = str(py_file.relative_to(repo_root))
        if any(rel.startswith(a) for a in ALLOWED_CLIENT_CONSTRUCTORS):
            continue
        tree = ast.parse(py_file.read_text())
        for node in ast.walk(tree):
            if isinstance(node, ast.Call):
                func = node.func
                if isinstance(func, ast.Attribute) and func.attr in (
                    "AsyncAnthropic", "Anthropic"
                ):
                    violations.append((rel, node.lineno))
                elif isinstance(func, ast.Name) and func.id in (
                    "AsyncAnthropic", "Anthropic"
                ):
                    violations.append((rel, node.lineno))
    return violations

def test_client_constructed_only_in_integration_layer():
    """AsyncAnthropic/Anthropic must only be instantiated in the integration layer."""
    repo_root = pathlib.Path(__file__).parent.parent.parent
    violations = find_client_constructors(repo_root)
    assert not violations, (
        "Client constructor called outside integration layer:\n" +
        "\n".join(f"  {f}:{l}" for f, l in violations)
    )

