import ast, pathlib

def modules_with_missing_structlog(repo_root: pathlib.Path) -> list[str]:
    violations = []
    for py_file in repo_root.glob("src/**/*.py"):
        rel = str(py_file.relative_to(repo_root))
        tree = ast.parse(py_file.read_text())
        imports = set()
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom)):
                for alias in node.names:
                    imports.add(alias.name or "")
                if isinstance(node, ast.ImportFrom) and node.module:
                    imports.add(node.module)
        has_anthropic = any("anthropic" in i for i in imports)
        has_structlog = any("structlog" in i for i in imports)
        if has_anthropic and not has_structlog:
            violations.append(rel)
    return violations

def test_anthropic_callers_use_structlog():
    """Every module that imports the Anthropic SDK must also import structlog."""
    repo_root = pathlib.Path(__file__).parent.parent.parent
    violations = modules_with_missing_structlog(repo_root)
    assert not violations, (
        "Modules calling Claude API without structlog:\n" +
        "\n".join(f"  {v}" for v in violations)
    )

# tests/architecture/test_resilience_fitness.py
import ast, pathlib

def find_unwrapped_api_calls(repo_root: pathlib.Path) -> list[tuple[str, int]]:
    """Find messages.create() calls not inside a circuit_breaker() context manager."""
    violations = []
    for py_file in repo_root.glob("src/claude/**/*.py"):
        rel = str(py_file.relative_to(repo_root))
        tree = ast.parse(py_file.read_text())

        for func_node in ast.walk(tree):
            if not isinstance(func_node, (ast.AsyncFunctionDef, ast.FunctionDef)):
                continue
            # Find all messages.create calls in this function
            create_calls = []
            cb_contexts = []
            for node in ast.walk(func_node):
                if isinstance(node, ast.Call):
                    if (isinstance(node.func, ast.Attribute) and
                            node.func.attr == "create" and
                            isinstance(node.func.value, ast.Attribute) and
                            node.func.value.attr == "messages"):
                        create_calls.append(node.lineno)
                if isinstance(node, ast.AsyncWith):
                    for item in node.items:
                        if (isinstance(item.context_expr, ast.Call) and
                                isinstance(item.context_expr.func, ast.Name) and
                                "circuit" in item.context_expr.func.id.lower()):
                            cb_contexts.append(node.lineno)

            if create_calls and not cb_contexts:
                for line in create_calls:
                    violations.append((rel, line))
    return violations

def test_all_api_calls_wrapped_in_circuit_breaker():
    """Every messages.create() call must be inside a circuit breaker context."""
    repo_root = pathlib.Path(__file__).parent.parent.parent
    violations = find_unwrapped_api_calls(repo_root)
    assert not violations, (
        "API calls not wrapped in circuit breaker:\n" +
        "\n".join(f"  {f}:{l}" for f, l in violations)
    )

