import ast, re, pathlib

# Heuristic: system prompt strings are > 100 chars and contain certain keywords
PROMPT_INDICATORS = re.compile(
    r"(you are|your role|do not|must not|capability|constraint|task is)", re.I
)

def find_inline_prompts(repo_root: pathlib.Path) -> list[tuple[str, int, str]]:
    violations = []
    for py_file in repo_root.glob("src/**/*.py"):
        rel = str(py_file.relative_to(repo_root))
        tree = ast.parse(py_file.read_text())
        for node in ast.walk(tree):
            if isinstance(node, ast.Constant) and isinstance(node.value, str):
                val = node.value
                if len(val) > 100 and PROMPT_INDICATORS.search(val):
                    violations.append((rel, node.lineno, val[:60] + "..."))
    return violations

def test_no_inline_system_prompts():
    """System prompt strings must not appear inline in application code.
    Load them from the template registry instead."""
    repo_root = pathlib.Path(__file__).parent.parent.parent
    violations = find_inline_prompts(repo_root)
    assert not violations, (
        "Likely inline system prompts found (load from registry instead):\n" +
        "\n".join(f"  {f}:{l} — {preview!r}" for f, l, preview in violations)
    )
